  textMuted: '#556677',
  green: '#22c55e',
  red: '#ef4444',
  amber: '#eab308',
  blue: '#60a5fa',
  purple: '#a78bfa',
  monoFont: "'JetBrains Mono', 'SF Mono', monospace",
  bodyFont: "'Plus Jakarta Sans', -apple-system, sans-serif",
