const LIVE_FEED = [
  { text: 'NVDA Long +1.8%', time: '2m ago', type: 'win' },
  { text: 'BTC Breakout Signal', time: '5m ago', type: 'signal' },
  { text: 'SPY Short Closed +0.6%', time: '12m ago', type: 'win' },
  { text: 'AAPL Pullback Entry', time: '18m ago', type: 'signal' },
  { text: 'ETH Momentum -0.4%', time: '25m ago', type: 'loss' },
]

/* ── Pill toggle button ── */
function Pill({ label, active, onClick }) {
  return (
    <button
      onClick={onClick}
      style={{
        padding: '6px 16px',
        borderRadius: 9999,
        border: `1px solid ${active ? T.blue : T.surfaceBorder}`,
        background: active ? 'rgba(96,165,250,0.15)' : 'transparent',
        color: active ? T.blue : T.textSecondary,
        fontSize: 13,
        fontWeight: active ? 600 : 500,
        fontFamily: T.bodyFont,
        cursor: 'pointer',
        transition: 'all 0.15s ease',
        whiteSpace: 'nowrap',
      }}
    >
      {label}
    </button>
  )
}

/* ── Status badge ── */
function StatusBadge({ status }) {
  const colors = {
    live: T.green,
    paper: T.amber,
    suppressed: T.red,
  }
  const color = colors[status] || T.textMuted
  return (
    <span style={{
      display: 'inline-block',
      padding: '3px 10px',
      borderRadius: 9999,
      fontSize: 11,
      fontWeight: 600,
      fontFamily: T.bodyFont,
      textTransform: 'capitalize',
      color: color,
      background: color + '1a',
      letterSpacing: '0.02em',
    }}>
      {status}
    </span>
  )
}

/* ── Evolution score ── */
function EvolutionScore({ score }) {
  const color = score >= 80 ? T.green : score >= 60 ? T.amber : T.red
  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
      <span style={{
        fontFamily: T.monoFont,
        fontSize: 13,
        fontWeight: 600,
        color: color,
      }}>
        {score}
      </span>
      <div style={{
        width: 48,
        height: 4,
        borderRadius: 2,
        background: 'rgba(255,255,255,0.06)',
        overflow: 'hidden',
      }}>
        <div style={{
          width: `${score}%`,
          height: '100%',
          borderRadius: 2,
          background: color,
          transition: 'width 0.4s ease',
        }} />
      </div>
    </div>
  )
}

/* ── Feed item ── */
function FeedItem({ item }) {
  const colors = { win: T.green, signal: T.blue, loss: T.red }
  const dotColor = colors[item.type] || T.textMuted
  return (
    <div style={{
      display: 'flex',
      alignItems: 'center',
      gap: 10,
      padding: '8px 16px',
      background: T.surface,
      border: `1px solid ${T.surfaceBorder}`,
      borderRadius: 10,
      whiteSpace: 'nowrap',
      flexShrink: 0,
    }}>
      <span style={{
        width: 7,
        height: 7,
        borderRadius: '50%',
        background: dotColor,
        boxShadow: `0 0 6px ${dotColor}66`,
        flexShrink: 0,
      }} />
      <span style={{
        fontSize: 13,
        fontFamily: T.monoFont,
        fontWeight: 500,
        color: colors[item.type],
      }}>
        {item.text}
      </span>
      <span style={{
        fontSize: 11,
        color: T.textMuted,
        fontFamily: T.bodyFont,
      }}>
        {item.time}
      </span>
    </div>
  )
}

/* ── Filter bar ── */
function FilterBar({ timeframe, setTimeframe, market, setMarket, status, setStatus, sortBy, setSortBy }) {
  return (
    <div style={{
      display: 'flex',
      flexWrap: 'wrap',
      gap: 24,
      padding: '20px 24px',
      background: T.surface,
      border: `1px solid ${T.surfaceBorder}`,
      borderRadius: 14,
      marginBottom: 24,
    }}>
      {/* Timeframe */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
        <span style={{ fontSize: 10, fontWeight: 600, color: T.textMuted, textTransform: 'uppercase', letterSpacing: '0.08em', fontFamily: T.bodyFont }}>Timeframe</span>
        <div style={{ display: 'flex', gap: 4 }}>
          {['7d', '30d', '90d', 'All'].map(t => (
            <Pill key={t} label={t} active={timeframe === t} onClick={() => setTimeframe(t)} />
          ))}
        </div>
      </div>

      {/* Market */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
        <span style={{ fontSize: 10, fontWeight: 600, color: T.textMuted, textTransform: 'uppercase', letterSpacing: '0.08em', fontFamily: T.bodyFont }}>Market</span>
        <div style={{ display: 'flex', gap: 4 }}>
          {['All', 'Equities', 'Crypto'].map(m => (
            <Pill key={m} label={m} active={market === m} onClick={() => setMarket(m)} />
          ))}
        </div>
      </div>

      {/* Status */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
        <span style={{ fontSize: 10, fontWeight: 600, color: T.textMuted, textTransform: 'uppercase', letterSpacing: '0.08em', fontFamily: T.bodyFont }}>Status</span>
        <div style={{ display: 'flex', gap: 4 }}>
          {['Live', 'Paper', 'Suppressed'].map(s => (
            <Pill key={s} label={s} active={status === s} onClick={() => setStatus(s)} />
          ))}
        </div>
      </div>

      {/* Sort By */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
        <span style={{ fontSize: 10, fontWeight: 600, color: T.textMuted, textTransform: 'uppercase', letterSpacing: '0.08em', fontFamily: T.bodyFont }}>Sort By</span>
        <div style={{ display: 'flex', gap: 4 }}>
          {['Return', 'Sharpe', 'Drawdown'].map(s => (
            <Pill key={s} label={s} active={sortBy === s} onClick={() => setSortBy(s)} />
          ))}
        </div>
      </div>
    </div>
  )
}

/* ── Strategy table ── */
function StrategyTable({ strategies }) {
  const cols = [
    { key: 'name', label: 'Strategy Name', align: 'left' },
    { key: 'market', label: 'Market', align: 'left' },
    { key: 'return_pct', label: 'Return %', align: 'right' },
    { key: 'win_rate', label: 'Win Rate', align: 'right' },
    { key: 'max_dd', label: 'Max Drawdown', align: 'right' },
    { key: 'status', label: 'Status', align: 'center' },
    { key: 'evolution', label: 'Evolution Score', align: 'center' },
  ]

  return (
    <div style={{
      border: `1px solid ${T.surfaceBorder}`,
      borderRadius: 14,
      overflow: 'hidden',
    }}>
      <div style={{ overflowX: 'auto' }}>
        <table style={{
          width: '100%',
          borderCollapse: 'collapse',
          fontFamily: T.bodyFont,
        }}>
          <thead>
            <tr>
              {cols.map(col => (
                <th key={col.key} style={{
                  padding: '14px 16px',
                  textAlign: col.align,
                  fontSize: 11,
                  fontWeight: 600,
                  color: T.textMuted,
                  textTransform: 'uppercase',
                  letterSpacing: '0.08em',
                  borderBottom: `1px solid ${T.surfaceBorder}`,
                  background: 'rgba(255,255,255,0.02)',
                  whiteSpace: 'nowrap',
                }}>
                  {col.label}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {strategies.map((s, i) => (
              <tr key={s.name} style={{
                background: i % 2 === 0 ? 'rgba(255,255,255,0.02)' : 'transparent',
                transition: 'background 0.15s ease',
              }}
                onMouseEnter={e => { e.currentTarget.style.background = 'rgba(255,255,255,0.05)' }}
                onMouseLeave={e => { e.currentTarget.style.background = i % 2 === 0 ? 'rgba(255,255,255,0.02)' : 'transparent' }}
              >
                <td style={{
                  padding: '14px 16px',
                  fontSize: 14,
                  fontWeight: 600,
                  color: T.textPrimary,
                  whiteSpace: 'nowrap',
                }}>
                  {s.name}
                </td>
                <td style={{
                  padding: '14px 16px',
                  fontSize: 13,
                  color: T.textSecondary,
                }}>
                  {s.market}
                </td>
                <td style={{
                  padding: '14px 16px',
                  textAlign: 'right',
                  fontFamily: T.monoFont,
                  fontSize: 14,
                  fontWeight: 600,
                  color: s.return_pct >= 0 ? T.green : T.red,
                }}>
                  {s.return_pct >= 0 ? '+' : ''}{s.return_pct}%
                </td>
                <td style={{
                  padding: '14px 16px',
                  textAlign: 'right',
                  fontFamily: T.monoFont,
                  fontSize: 13,
                  fontWeight: 500,
                  color: T.textPrimary,
                }}>
                  {s.win_rate}%
                </td>
                <td style={{
                  padding: '14px 16px',
                  textAlign: 'right',
                  fontFamily: T.monoFont,
                  fontSize: 13,
                  fontWeight: 500,
                  color: T.red,
                }}>
                  {s.max_dd}%
                </td>
                <td style={{
                  padding: '14px 16px',
                  textAlign: 'center',
                }}>
                  <StatusBadge status={s.status} />
                </td>
                <td style={{
                  padding: '14px 16px',
                  textAlign: 'center',
                }}>
                  <EvolutionScore score={s.evolution} />
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  )
}

/* ═══════════════════════════════════════════════════════════════════════════
   STRATEGY LEADERBOARD PAGE — Public strategy performance transparency
   ═══════════════════════════════════════════════════════════════════════════ */
export default function StrategyLeaderboardPage() {
  const [timeframe, setTimeframe] = useState('30d')
  const [market, setMarket] = useState('All')
  const [status, setStatus] = useState('Live')
  const [sortBy, setSortBy] = useState('Return')
  const [strategies, setStrategies] = useState(MOCK)
  const [loading, setLoading] = useState(true)

  /* Fetch strategies from API, fall back to mock */
  useEffect(() => {
    let cancelled = false
    async function load() {
      try {
        const res = await fetch('/api/strategies')
        if (!res.ok) throw new Error('API unavailable')
        const data = await res.json()
        if (!cancelled && Array.isArray(data) && data.length > 0) {
          setStrategies(data)
        }
      } catch {
        // Use mock data — already set as default
      } finally {
        if (!cancelled) setLoading(false)
      }
    }
    load()
    return () => { cancelled = true }
  }, [])

  /* Filter + sort */
  const filtered = useMemo(() => {
    let result = [...strategies]

    // Filter by market
    if (market !== 'All') {
      result = result.filter(s => s.market === market)
    }

    // Filter by status
    result = result.filter(s => s.status === status.toLowerCase())

    // Sort
    if (sortBy === 'Return') {
      result.sort((a, b) => b.return_pct - a.return_pct)
    } else if (sortBy === 'Sharpe') {
      result.sort((a, b) => (b.return_pct / Math.abs(b.max_dd)) - (a.return_pct / Math.abs(a.max_dd)))
    } else if (sortBy === 'Drawdown') {
      result.sort((a, b) => a.max_dd - b.max_dd)
    }

    return result
  }, [strategies, market, status, sortBy])

  return (
    <div style={{
      minHeight: '100vh',
      background: T.bg,
      color: T.textPrimary,
      fontFamily: T.bodyFont,
    }}>
      <PublicNav />

      {/* ── Hero ── */}
      <section style={{
        padding: '100px 24px 48px',
        textAlign: 'center',
        maxWidth: 800,
        margin: '0 auto',
      }}>
        <h1 style={{
          fontSize: 48,
          fontWeight: 800,
          letterSpacing: '-0.03em',
          lineHeight: 1.1,
          margin: 0,
          background: 'linear-gradient(135deg, #E8ECF1 0%, #8899AA 100%)',
          WebkitBackgroundClip: 'text',
          WebkitTextFillColor: 'transparent',
        }}>
          Strategy Leaderboard
        </h1>
        <p style={{
          fontSize: 18,
          color: T.textSecondary,
          marginTop: 16,
          lineHeight: 1.6,
        }}>
          Live performance across all strategies. Every result tracked. Every system transparent.
        </p>
        <Link to="/register" style={{
          display: 'inline-block',
          marginTop: 28,
          padding: '12px 32px',
          borderRadius: 10,
          background: 'linear-gradient(135deg, #60A5FA 0%, #A78BFA 100%)',
          color: '#fff',
          fontSize: 15,
          fontWeight: 600,
          textDecoration: 'none',
          transition: 'opacity 0.15s ease',
        }}
          onMouseEnter={e => { e.target.style.opacity = '0.85' }}
          onMouseLeave={e => { e.target.style.opacity = '1' }}
        >
          Run These Strategies
        </Link>
      </section>

      {/* ── Trust line ── */}
      <div style={{
        textAlign: 'center',
        padding: '0 24px 40px',
      }}>
        <div style={{
          display: 'inline-flex',
          alignItems: 'center',
          gap: 10,
          padding: '10px 24px',
          background: T.surface,
          border: `1px solid ${T.surfaceBorder}`,
          borderRadius: 9999,
        }}>
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke={T.green} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z" /><path d="M9 12l2 2 4-4" />
          </svg>
          <span style={{
            fontSize: 13,
            fontWeight: 500,
            color: T.textSecondary,
          }}>
            All strategies are walk-forward validated. No cherry-picking. No hidden results.
          </span>
        </div>
      </div>

      {/* ── Main content ── */}
      <div style={{
        maxWidth: 1200,
        margin: '0 auto',
        padding: '0 24px 80px',
      }}>

        {/* ── Live activity feed ── */}
        <div style={{ marginBottom: 24 }}>
          <div style={{
            display: 'flex',
            alignItems: 'center',
            gap: 8,
            marginBottom: 12,
          }}>
            <span style={{
              width: 8,
              height: 8,
              borderRadius: '50%',
              background: T.green,
              boxShadow: `0 0 8px ${T.green}66`,
              animation: 'lbPulse 2s ease-in-out infinite',
            }} />
            <span style={{
              fontSize: 12,
              fontWeight: 600,
              color: T.textMuted,
              textTransform: 'uppercase',
              letterSpacing: '0.08em',
              fontFamily: T.bodyFont,
            }}>
              Live Activity
            </span>
          </div>
          <div style={{
            display: 'flex',
            gap: 10,
            overflowX: 'auto',
            paddingBottom: 4,
            scrollbarWidth: 'thin',
          }}>
            {LIVE_FEED.map((item, i) => (
              <FeedItem key={i} item={item} />
            ))}
          </div>
        </div>

        {/* ── Filter bar ── */}
        <FilterBar
          timeframe={timeframe} setTimeframe={setTimeframe}
          market={market} setMarket={setMarket}
          status={status} setStatus={setStatus}
          sortBy={sortBy} setSortBy={setSortBy}
        />

        {/* ── Strategy table ── */}
        {loading ? (
          <div style={{
            textAlign: 'center',
            padding: '60px 0',
            color: T.textMuted,
            fontSize: 14,
          }}>
            Loading strategies...
          </div>
        ) : filtered.length === 0 ? (
          <div style={{
            textAlign: 'center',
            padding: '60px 0',
            color: T.textMuted,
            fontSize: 14,
          }}>
            No strategies match the current filters.
          </div>
        ) : (
          <StrategyTable strategies={filtered} />
        )}

        {/* ── Result count ── */}
        <div style={{
          marginTop: 16,
          textAlign: 'right',
          fontSize: 12,
          color: T.textMuted,
          fontFamily: T.monoFont,
        }}>
          {filtered.length} strateg{filtered.length === 1 ? 'y' : 'ies'} shown
        </div>
      </div>

      {/* ── Bottom CTA ── */}
      <section style={{
        padding: '64px 24px 80px',
        textAlign: 'center',
        borderTop: `1px solid ${T.surfaceBorder}`,
      }}>
        <p style={{
          fontSize: 20,
          fontWeight: 600,
          color: T.textPrimary,
          maxWidth: 600,
          margin: '0 auto',
          lineHeight: 1.5,
        }}>
          These strategies are already running. Start compounding with them today.
        </p>
        <Link to="/register" style={{
          display: 'inline-block',
          marginTop: 24,
          padding: '14px 36px',
          borderRadius: 12,
          background: 'linear-gradient(135deg, #60A5FA 0%, #A78BFA 100%)',
          color: '#fff',
          fontSize: 16,
          fontWeight: 700,
          textDecoration: 'none',
          transition: 'opacity 0.15s ease',
          boxShadow: '0 0 24px rgba(96,165,250,0.25)',
        }}
          onMouseEnter={e => { e.target.style.opacity = '0.85' }}
          onMouseLeave={e => { e.target.style.opacity = '1' }}
        >
          Deploy These Strategies
        </Link>
      </section>

      <PublicFooter />

      {/* Pulse animation for live dot */}
      <style>{`
        @keyframes lbPulse {
          0%, 100% { opacity: 1; }
          50% { opacity: 0.4; }
        }
      `}</style>
    </div>
  )
}
